// Import a private key.
func (c *Client) ImportPrivateKey(ctx context.Context, input ImportPrivateKeyRequest) (*ImportPrivateKeyResponse, error) {
	body, err := c.activityEnvelope(input)
	if err != nil {
		return nil, err
	}
	var raw map[string]any
	if err := c.postJSON(ctx, c.config.urls.baseURL, "/public/v1/submit/import_private_key", body, &raw, true, nil); err != nil {
		return nil, err
	}
	out := new(ActivityResult[ImportPrivateKeyResult])
	if err := decodeActivityResponse(raw, "ImportPrivateKeyResult", out); err != nil {
		return nil, err
	}
	result, activity, err := activityAndWait(ctx, c, out, func(r Result) *ImportPrivateKeyResult { return r.ImportPrivateKeyResult })
	if err != nil {
		return nil, err
	}
	return &ImportPrivateKeyResponse{Activity: *activity, ImportPrivateKeyResult: *result}, nil
}

